fun onRefresh() {
    refreshJob?.cancel()
    refreshJob = viewModelScope.launch {
        _uiState.update { it.copy(isRefreshing = true) }
        try {
            repository.refresh()
        } finally {
            _uiState.update { it.copy(isRefreshing = false) }
        }
    }
}

suspend fun loadJobDetail(jobId: String): JobDetail = coroutineScope {
    val job = async { jobRepository.getJob(jobId) }
    val saved = async { savedRepository.isSaved(jobId) }
    val company = async { companyRepository.getByJob(jobId) }

    JobDetail(
        job = job.await(),
        isSaved = saved.await(),
        company = company.await()
    )
}

class AvatarRepository(
    private val ioDispatcher: CoroutineDispatcher
) {
    suspend fun readAvatar(file: File): ByteArray =
        withContext(ioDispatcher) {
            file.readBytes()
        }
}

suspend fun load(jobId: String): JobDetailState = supervisorScope {
    val core = async { jobRepository.getJob(jobId) }
    val saved = async { runCatching { savedRepository.isSaved(jobId) } }
    val company = async { runCatching { companyRepository.getByJob(jobId) } }

    JobDetailState.Content(
        job = core.await(),
        isSaved = saved.await().getOrDefault(false),
        company = company.await().getOrNull()
    )
}

inline fun <T> captureResult(block: () -> T): Result<T> =
    try { Result.success(block()) }
    catch (e: CancellationException) { throw e }
    catch (t: Throwable) { Result.failure(t) }
